INSERT INTO quiz_questions (set_id, question_id, question, options, correct_option_index, explanation, sort_order) VALUES
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_51', '디랙 방정식이 예측한 것은?', '["중력파","반물질(양전자)의 존재","핵분열","블랙홀"]', 1, '1928년 디랙 방정식은 양전자(반물질)의 존재를 예측했습니다.', 51),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_52', '초유체(Superfluid)의 특징은?', '["매우 뜨거움","점성이 0이 되어 마찰 없이 흐름","전도체가 됨","자성을 가짐"]', 1, '초유체(예: 헬륨-4, 극저온)는 점성 없이 용기 벽을 타고 흐릅니다.', 52),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_53', '양자 홀 효과란?', '["홀의 법칙","2차원 전자 시스템에서 자기장 하에 홀 전도도가 양자화되는 현상","홀의 온도","홀의 압력"]', 1, '양자 홀 효과(1980, 노벨상 1985): 홀 전도도가 e²/h의 정수배.', 53),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_54', '그래핀의 특징이 아닌 것은?', '["탄소 원자 한 층","매우 높은 전기 전도도","매우 약함","높은 인장 강도"]', 2, '그래핀은 강철보다 200배 강한 탄소 나노물질입니다.', 54),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_55', '양자 점(Quantum dot)이란?', '["양자 컴퓨터의 점","나노미터 크기의 반도체 결정으로 크기에 따라 색이 변함","점 모양 별","양자 상태"]', 1, '양자 점은 크기에 따라 밴드갭이 변하여 다른 색의 빛을 방출합니다.', 55),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_56', '중력자(Graviton)란?', '["이미 발견된 입자","중력을 매개할 것으로 이론적으로 예측되나 미발견","광자의 별명","전자의 일종"]', 1, '중력자는 양자 중력 이론에서 예측되는 스핀-2 보손입니다.', 56),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_57', '라플라스 방정식은 어느 분야에서 중요하나요?', '["생물학","전자기학, 유체역학, 중력 포텐셜","유전학","화학반응학"]', 1, '∇²φ=0은 정전기학, 유체역학 등 다양한 분야에서 사용됩니다.', 57),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_58', '사건의 지평선(Event horizon)이란?', '["일상적 경계","블랙홀 주변에서 빛도 탈출 불가한 경계","시간의 끝","공간의 시작"]', 1, '사건의 지평선 안으로 들어간 빛은 다시 나올 수 없습니다.', 58),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_59', '첸-사이먼스(Chern-Simons) 이론은 어떤 분야에 사용되나요?', '["고전역학","위상 양자장론과 매듭 이론","열역학","유기화학"]', 1, 'Chern-Simons 이론은 위상 양자장론에서 중요한 역할을 합니다.', 59),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_60', '산화 그래핀(GO)이 연구되는 이유는?', '["먹을 수 있어서","물 정화, 에너지 저장, 복합재료 등 다양한 응용","장식용","소리 차단"]', 1, '산화 그래핀은 물 분리막, 슈퍼커패시터 등에 활용이 기대됩니다.', 60),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_61', 'LIGO의 팔 길이는 약?', '["1m","100m","4km","400km"]', 2, 'LIGO의 레이저 간섭계 팔 길이는 약 4km입니다.', 61),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_62', '와인버그-살람 모형이란?', '["핵분열 모형","전자기 약력 통일 이론","중력 이론","초끈 이론"]', 1, '전자기력과 약한 핵력을 통합한 전약(Electroweak) 이론.', 62),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_63', '점근 자유(Asymptotic freedom)란?', '["자유 입자","쿼크 간 거리가 가까울수록 강한 핵력이 약해지는 현상","핵분열","자기 자유"]', 1, '2004년 노벨상: 쿼크는 가까이 있을수록 거의 자유 입자처럼 행동.', 63),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_64', '뇌-컴퓨터 인터페이스(BCI)의 목적은?', '["뇌를 컴퓨터로 대체","뇌 신경 신호를 읽어 외부 기기를 제어","뇌 수술","컴퓨터로 생각"]', 1, 'BCI는 신경 신호를 해독하여 의수, 커서 이동 등을 구현합니다.', 64),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_65', '합성 생물학(Synthetic biology)이란?', '["인공 생명체 창조만","생물 시스템을 설계하고 구축하는 공학적 생물학","유전자 분석만","생물 그림"]', 1, '유전자 회로, 인공 세포 등을 설계·구축하는 학문입니다.', 65),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_66', 'CAR-T 세포 치료란?', '["자동차 관련 치료","환자의 T세포를 변형하여 암을 공격하도록 하는 면역치료","방사선 치료","화학 치료"]', 1, '키메라 항원 수용체 T세포(CAR-T)로 종양 세포를 공격합니다.', 66),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_67', '알파폴드(AlphaFold)가 해결한 문제는?', '["체스","단백질 3D 구조 예측","날씨 예측","주가 예측"]', 1, 'DeepMind의 AlphaFold는 아미노산 서열에서 단백질 구조를 예측.', 67),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_68', '파인만 다이어그램의 용도는?', '["건축 설계","양자장론에서 입자 상호작용을 시각화하고 계산","회로도","분자 구조"]', 1, '파인만 다이어그램으로 산란 진폭을 체계적으로 계산합니다.', 68),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_69', '자발적 대칭 깨짐(Spontaneous symmetry breaking)이란?', '["대칭이 항상 유지","물리 법칙은 대칭적이지만 기저 상태는 대칭이 깨질 수 있다","무질서","무작위"]', 1, '힉스 메커니즘의 핵심으로, 입자 질량의 기원을 설명합니다.', 69),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_70', '위그너의 친구 사고실험은 무엇을 탐구하나요?', '["우정","양자역학의 관측 문제와 측정의 의미","열역학","유전학"]', 1, '관측자에 따라 양자 상태가 달라질 수 있는가 하는 문제를 다룹니다.', 70),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_71', '양자 오류 보정이 중요한 이유는?', '["오류가 없어서","양자 비트는 환경 노이즈에 매우 취약하여 오류 보정 없이는 대규모 양자 연산 불가","비용 때문","속도 때문"]', 1, '결어긋남(decoherence)에 의한 정보 손실을 보정해야 합니다.', 71),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_72', '조지프슨 효과란?', '["자기장 효과","두 초전도체 사이 얇은 절연층에서 전자쌍이 터널링하는 현상","광전 효과","피에조 효과"]', 1, '조지프슨 접합은 초전도 양자 소자(SQUID 등)에 사용됩니다.', 72),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_73', '펩타이드 결합이란?', '["금속 결합","두 아미노산 사이 탈수 축합 반응으로 형성되는 공유 결합","이온 결합","수소 결합"]', 1, '아미노산의 아미노기와 카르복시기가 물을 잃으며 결합합니다.', 73),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_74', '랜도어의 원리란?', '["에너지 보존","1비트의 정보를 삭제할 때 최소 kT ln2의 열이 발생","질량 보존","운동 법칙"]', 1, '정보와 열역학의 연결: 정보 삭제에는 최소한의 에너지가 필요.', 74),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_75', '네거엔트로피(Negentropy)란?', '["높은 무질서도","엔트로피의 감소 또는 질서 증가를 측정","중성 엔트로피","에너지 단위"]', 1, '슈뢰딩거가 제안한 개념으로, 생명체의 질서 유지와 관련.', 75),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_76', '측지선(Geodesic)이란?', '["직선","휘어진 시공간에서 가장 짧은(또는 극값) 경로","곡면 없는 평면","수평선"]', 1, '일반 상대성 이론에서 자유 낙하 입자는 측지선을 따라 이동.', 76),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_77', '양자 전기역학(QED)을 발전시킨 과학자는?', '["아인슈타인","파인만, 슈윙거, 도모나가","보어","하이젠베르크"]', 1, '1965년 노벨상: QED는 가장 정밀한 물리 이론 중 하나.', 77),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_78', '타리이온자(Tardigrade)가 극한 환경에서 생존하는 이유는?', '["몸이 큰 덕분","건조 휴면 상태(tun state)로 대사를 거의 정지","빠른 번식","강한 면역"]', 1, '물곰은 건조, 우주 진공, 방사선에도 생존할 수 있습니다.', 78),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_79', 'ITER 프로젝트의 목표는?', '["핵분열 발전","핵융합 발전의 실현 가능성 입증","소행성 탐사","인공위성 발사"]', 1, 'ITER는 국제 공동 핵융합 실험 프로젝트(프랑스 건설 중)입니다.', 79),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_80', '토카막이란?', '["레이저 장치","자기장으로 플라스마를 가두는 도넛 형태의 핵융합 장치","망원경","가속기"]', 1, '토카막은 자기 가둠 핵융합의 가장 유력한 방식입니다.', 80),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_81', '미세 플라스틱이 주목받는 이유는?', '["유용해서","환경과 생물체에 축적되어 건강과 생태계에 해로운 영향","아름다워서","전기를 만들어서"]', 1, '5mm 이하의 플라스틱 조각이 해양 생태계와 먹이사슬에 유입.', 81),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_82', '유전자 드라이브(Gene drive)란?', '["운전 유전자","유전자를 개체군 전체에 빠르게 퍼뜨리는 기술","유전자 삭제","유전자 분석"]', 1, '말라리아 모기 퇴치 등에 활용이 논의되는 유전 공학 기술.', 82),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_83', '카본 나노튜브의 특징은?', '["약하고 무거움","매우 강하고 전기와 열 전도성이 우수한 탄소 구조물","액체 상태","방사성"]', 1, '탄소 원자가 원통형으로 배열된 나노물질, 강도가 매우 높습니다.', 83),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_84', '슈바르츠실트 반지름이란?', '["별의 반지름","질량이 주어졌을 때 블랙홀이 되기 위한 사건의 지평선 반지름","은하 반지름","원자 반지름"]', 1, 'r_s = 2GM/c² (물체가 이보다 작아지면 블랙홀이 됩니다).', 84),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_85', '양성자 치료(Proton therapy)의 장점은?', '["저렴함","종양에 정확히 에너지를 집중(브래그 피크)하여 주변 조직 손상 최소화","빠른 치료","약물 불필요"]', 1, '양성자의 브래그 피크를 이용해 종양에만 에너지를 집중합니다.', 85),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_86', '스핀트로닉스란?', '["회전 역학","전자의 스핀을 이용한 정보 저장·처리 기술","자동차 기술","광학 기술"]', 1, '전자의 전하뿐 아니라 스핀도 활용하는 차세대 전자공학입니다.', 86),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_87', '광결정(Photonic crystal)이란?', '["보석","주기적 유전체 구조로 특정 파장의 빛을 차단/제어하는 물질","일반 결정","액체 결정"]', 1, '광결정은 광학적 밴드갭으로 특정 파장의 빛 전파를 제어합니다.', 87),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_88', '열전 소자(Thermoelectric device)의 원리는?', '["화학 반응","온도 차이를 전기로, 또는 전기를 온도 차이로 변환(제벡/펠티에 효과)","핵반응","광전 효과"]', 1, '제벡 효과(발전)와 펠티에 효과(냉각)를 이용합니다.', 88),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_89', '암흑 에너지와 우주 상수(Λ)의 관계는?', '["관계 없음","우주 상수가 암흑 에너지의 가장 단순한 후보로 간주됨","우주 상수가 0","암흑 물질과 같음"]', 1, '아인슈타인의 우주 상수가 암흑 에너지의 가장 단순한 모델.', 89),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_90', '다세계 해석(Many-worlds interpretation)이란?', '["평행 우주가 실존하는 물리학","양자 측정 시 모든 가능한 결과가 각각 다른 분기 세계에서 실현된다는 해석","SF 소설","다중 은하"]', 1, '에버렛의 해석: 파동함수 붕괴 대신 분기를 통해 모든 결과가 실현.', 90),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_91', 'RNA 간섭(RNAi)이란?', '["RNA가 간섭 없이 작동","짧은 RNA 분자가 특정 유전자의 발현을 억제하는 메커니즘","RNA 파괴","DNA 복제"]', 1, 'siRNA/miRNA가 상보적 mRNA에 결합하여 유전자 발현을 침묵시킴.', 91),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_92', '위상 절연체(Topological insulator)란?', '["보통 절연체","내부는 절연체이지만 표면/가장자리에서 전도성 상태를 가지는 물질","반도체","초전도체"]', 1, '위상적으로 보호된 표면 상태가 존재하는 특수 물질입니다.', 92),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_93', '에디르 크라우지우스(Clausius)가 정의한 개념은?', '["에너지","엔트로피","질량","힘"]', 1, '클라우지우스는 1865년 엔트로피 개념을 정립했습니다.', 93),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_94', '맥스웰 방정식은 무엇을 통합했나요?', '["중력과 전자기력","전기와 자기 현상","양자역학과 상대론","열역학과 통계역학"]', 1, '맥스웰은 전기와 자기를 통합한 전자기학 방정식을 정립.', 94),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_95', '노이만 엔트로피란?', '["열역학적 엔트로피","양자 시스템의 정보 엔트로피를 밀도 행렬로 정의","화학 엔트로피","고전 엔트로피"]', 1, 'S = -Tr(ρ ln ρ)로 양자 역학적 혼합 상태의 불확실성을 측정.', 95),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_96', '극초단 레이저 펄스(Attosecond laser)의 활용은?', '["건축","전자의 운동을 실시간으로 관측(아토초 = 10⁻¹⁸ 초)","음악","요리"]', 1, '2023년 노벨 물리학상: 아토초 레이저로 전자 움직임 관측.', 96),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_97', '양자 우위/양자 이점(Quantum advantage)이란?', '["양자 컴퓨터만 존재하는 것","양자 컴퓨터가 고전 컴퓨터보다 특정 문제를 압도적으로 빠르게 해결","양자역학의 우월성","양자 암호"]', 1, '구글 시카모어(2019)가 양자 이점을 최초 주장했습니다.', 97),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_98', '카이랄 분자(Chiral molecule)란?', '["대칭 분자","거울상 이성질체가 겹치지 않는 분자","평면 분자","원형 분자"]', 1, '왼손-오른손처럼 거울상이 겹치지 않는 분자를 카이랄 분자라 함.', 98),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_99', '양자 키 분배(QKD)의 장점은?', '["빠른 전송","도청 시 양자 상태가 변해 도청 사실을 감지 가능","저렴함","무선 통신"]', 1, '양자역학 원리를 이용한 이론적으로 절대 안전한 암호 통신.', 99),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='science'), 'sc_g_100', '인류세(Anthropocene)란?', '["공룡 시대","인간 활동이 지구 환경에 중대한 영향을 미치는 새로운 지질 시대","빙하기","중생대"]', 1, '인류세는 인간 활동이 지질학적 변화를 야기하는 시대를 지칭.', 100)
